package genxsolution.vms.vmsbackend.maintenance_management.repair_job.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.repair_job.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.repair_job.mapper.RepairJobMapper; import genxsolution.vms.vmsbackend.maintenance_management.repair_job.repository.RepairJobRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class RepairJobService { private final RepairJobRepository repository; private final RepairJobMapper mapper; public RepairJobService(RepairJobRepository repository,RepairJobMapper mapper){this.repository=repository;this.mapper=mapper;} public List<RepairJobResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public RepairJobResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("RepairJob", String.valueOf(id))); } public RepairJobResponse create(RepairJobUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public RepairJobResponse update(UUID id,RepairJobUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("RepairJob", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("RepairJob", String.valueOf(id)); } }
